WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/33.0/connection.js")}
{!REQUIRESCRIPT("/soap/ajax/33.0/apex.js")}

var count = "{!Contact.IP_Allpayprofiles__c}"
var shiftframe = "{!$Label.ShiftTimeframestart}"
var shiftframe1 = "{!$Label.ShiftTimeframeend}"
var shiftnames = [];
var timesheetnames = [];
var timeresults = [];
var suppreason = "{!Contact.P45_Suppression_Reason__c}"

if(suppreason == 'Not Suppressed' || suppreason == '')
{

if(count>0)
{
if(count==1)
{
var shiftrec = sforce.connection.query("Select id,sirenum__Cancelled__c,name,sirenum__Published__c,sirenum__Timesheet_summaries__c,sirenum__Billable_Calculated_Start_Time__c from sirenum__shift__c where sirenum__Contact__c ='{!Contact.Id}' and sirenum__Published__c= TRUE and (sirenum__Cancelled__c=false and sirenum__Timesheet_summaries__c ='') and (sirenum__Billable_Calculated_Start_Time__c = null OR sirenum__Billable_Calculated_Start_Time__c=LAST_N_DAYS:"+shiftframe+" OR sirenum__Billable_Calculated_Start_Time__c=NEXT_N_DAYS:"+shiftframe1+")");

var shiftlist = shiftrec.getArray("records");

var timerec = sforce.connection.query("Select id,IP_LastPassedToTempest__c,IP_Locktimesheet__c,sirenum__Timesheet__r.sirenum__Worker__c,IP_PassToTempest__c,sirenum__Timesheet__r.Name,sirenum__Timesheet__r.IP_StandardWeeklyNumberID__c from sirenum__Timesheet_Line__c where sirenum__Timesheet__r.sirenum__Worker__c='{!Contact.Id}' and ((IP_LastPassedToTempest__c=null and IP_PassToTempest__c = TRUE and IP_Locktimesheet__c = FALSE) OR (IP_PassToTempest__c = TRUE and IP_Locktimesheet__c = FALSE))");

var timelist = timerec.getArray("records");

if(shiftlist.length>0 || timelist.length>0)
{
for(var i=0;i<shiftlist.length;i++)
{
var name = shiftlist[i].Name;
shiftnames.push(name);

}

if(timelist.length == 1)
{
for(var i=0;i<timelist.length;i++)
{
var name1 = timelist[i].sirenum__Timesheet__r.IP_StandardWeeklyNumberID__c;

timesheetnames.push(name1);
timeresults.push(name1);
}
}
else
{
for(var i=0;i<timelist.length;i++)
{
var name1 = timelist[i].sirenum__Timesheet__r.IP_StandardWeeklyNumberID__c;

timesheetnames.push(name1);
}

for (var i = 0; i <= timesheetnames.length - 1; i++) {
if (timesheetnames[i + 1] != timesheetnames[i]) {
timeresults.push(timesheetnames[i]);
}
}
}
if(shiftlist.length>0 && timelist.length>0)
{
alert('Candidate has the following timesheet(s) pending payroll. Please wait until the next payroll process has completed. \n '+'Timesheet ID: '+timeresults + '\n\nCandidate has the following active shift(s). Please cancel or reassign shifts before making Leaver Request. \n'+shiftnames)
}
else if(shiftlist.length>0)
{
alert('Candidate has the following active shift(s). Please cancel or reassign shifts before making Leaver Request. \n'+' '+shiftnames);
}
else
{
alert('Candidate has the following timesheet(s) pending payroll. Please wait until the next payroll process has completed. \n'+'Timesheet ID: '+timeresults);
}
}
else
{
window.open('/apex/CaptureReasonforLeaving?id={! Contact.Id}', '_blank', 'height=550,width=800,resizable=yes,scrollbars=yes,toolbar=n??o,menubar=no');
}


}
else
{
window.open('/apex/CandidateP45Action?id={! Contact.Id}', '_blank', 'height=550,width=800,resizable=yes,scrollbars=yes,toolbar=n??o,menubar=no');
}
}

else

{
alert('Only candidates with active pay profile(s) are qualified for Leaver Request.');
location.reload(true);
}
}
else
{
alert('Candidate has been P45 suppressed. Please remove the Suppression Reason before making the leaver request.');
location.reload(true);
}
